#include<bits/stdc++.h>
using namespace std;
long long a[100010],b[100010],rnk[100010],d[100010],siz[100010],fa[100010],top[100010],dfncnt,dfn[100010],son[100010],val[100010];
vector<long long> mp[100010];
void dfs1(long long x,long long f=-1)
{
    fa[x]=f;
    siz[x]=1;
    son[x]=-1;
    for(long long i:mp[x])
    {
        if(i!=f)
        {
            d[i]=d[x]+1;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    top[x]=t;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(long long i:mp[x])
        {
            if(i!=son[x]&&i!=fa[x])
            {
                dfs2(i,i);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long lval,rval,ans;
        long long tag;
    }t[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        long long ls=t[x].lson,rs=t[x].rson;
        t[x].lval=t[ls].lval;
        t[x].rval=t[rs].rval;
        t[x].ans=t[ls].ans+t[rs].ans+(long long)(t[ls].rval==t[rs].lval);
    }
    void pushup(node &x,node ls1,node rs1)
    {
        if(ls1.l==-1)
        {
            x=rs1;
            return;
        }
        if(rs1.l==-1)
        {
            x=ls1;
            return;
        }
        node ls=ls1,rs=rs1;
        x.lval=ls.lval;
        x.rval=rs.rval;
        x.ans=ls.ans+rs.ans+(long long)(ls.rval==rs.lval);
    }
    void pushupd(int x,int v)
    {
        t[x].lval=t[x].rval=v;
        t[x].ans=(t[x].r-t[x].l);
        t[x].tag=v;
    }
    void pushdown(int x)
    {
        int ls=t[x].lson,rs=t[x].rson;
        long long tg=t[x].tag;
        if(tg==-1)
        {
            return;
        }
        pushupd(ls,tg);
        pushupd(rs,tg);
        t[x].tag=-1;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        t[x].l=l;
        t[x].r=r;
        t[x].tag=-1;
        if(l==r)
        {
            t[x].lval=t[x].rval=l;
            t[x].ans=0;
            return x;
        }
        long long mid=(l+r)>>1;
        t[x].lson=init(l,mid);
        t[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r,long long v)
    {
        if(t[x].l>r||t[x].r<l)
        {
            return;
        }
        if(l<=t[x].l&&t[x].r<=r)
        {
            pushupd(x,v);
            return;
        }
        pushdown(x);
        update(t[x].lson,l,r,v);
        update(t[x].rson,l,r,v);
        pushup(x);
    }
    node query(long long x,long long l,long long r)
    {
        if(l<=t[x].l&&t[x].r<=r)
        {
            return t[x];
        }
        long long mid=(t[x].l+t[x].r)>>1;
        pushdown(x);
        if(l<=mid&&r>mid)
        {
            node ans=t[x];
            pushup(ans,query(t[x].lson,l,r),query(t[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(t[x].lson,l,r);
        }
        else
        {
            return query(t[x].rson,l,r);
        }
    }
}t;
long long getans(long long x,long long y)
{
    segment_tree::node ansl=(segment_tree::node){-1,0,0,0,0,0,0,0};
    auto ansr=ansl;
    int flag=true;
    while(top[x]!=top[y])
    {
        segment_tree::node now;
        if(d[top[x]]<d[top[y]])
        {
            flag=!flag;
            swap(x,y);
        }
        now=t.query(1,dfn[top[x]],dfn[x]);
        if(flag)
        {
            t.pushup(ansr,now,ansr);
        }
        else
        {
            swap(now.lval,now.rval);
            t.pushup(ansl,ansl,now);
        }
        x=fa[top[x]];
    }
    segment_tree::node now;
    if(d[x]<d[y])
    {
        swap(x,y);
        flag=!flag;
    }
    now=t.query(1,dfn[y],dfn[x]);
    if(flag)
    {
        t.pushup(ansr,now,ansr);
    }
    else
    {
        swap(now.lval,now.rval);
        t.pushup(ansl,ansl,now);
    }
    segment_tree::node ans;
    t.pushup(ans,ansl,ansr);
    return ans.ans;
}
void update(long long x,long long y,long long v)
{
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        t.update(1,dfn[top[x]],dfn[x],v);
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    t.update(1,dfn[x],dfn[y],v);
}
int main()
{
    long long T;
    scanf("%lld",&T);
    while(T--)
    {
        long long n,q;
        scanf("%lld%lld",&n,&q);
        for(long long i=1;i<=n;i++)
        {
            mp[i].clear();
        }
        memset(top,0,sizeof(top));
        memset(dfn,0,sizeof(dfn));
        dfncnt=0;
        for(long long i=1;i<n;i++)
        {
            long long u,v;
            scanf("%lld%lld",&u,&v);
            mp[u].push_back(v);
            mp[v].push_back(u);
        }
        dfs1(1);
        dfs2(1,1);
        t.cnt=0;
        t.init(1,n);
        for(int i=1;i<=q;i++)
        {
            long long op,a,b;
            scanf("%lld%lld%lld",&op,&a,&b);
            if(op==1)
            {
                update(a,b,i+n);
            }
            else
            {
                printf("%lld\n",getans(a,b));
            }
        }
    }
    return 0;
}
